+type GPUNodeHealthCheck struct {
+	Name    string `json:"name"`              // e.g., "node_ready", "gpu_feature_discovery"
+	Passed  bool   `json:"passed"`
+	Message string `json:"message,omitempty"` // e.g., "CrashLoopBackOff (128 restarts)"
